"use client";

import dynamic from "next/dynamic";
import { useDesignStore } from "@/stores/useDesignStore";

// Dynamically import the Scene to avoid SSR issues with Three.js / WebGL
const Scene = dynamic(() => import("@/components/scene/Scene"), {
  ssr: false,
});

/**
 * Client-side wrapper that reads bead chain state from the global Zustand
 * design store and passes it to the Scene.
 *
 * This is a temporary bridge — T03 will replace this with EditorCanvas.
 */
export default function SceneLoader() {
  const beads = useDesignStore((s) => s.beads);

  const handleAdd = () => {
    // Add the first catalog bead as a demo default
    useDesignStore.getState().addBead("cb-001");
  };

  const handleRemoveLast = () => {
    const currentBeads = useDesignStore.getState().beads;
    if (currentBeads.length > 0) {
      const lastBead = currentBeads[currentBeads.length - 1];
      useDesignStore.getState().removeBead(lastBead.id);
    }
  };

  const handleReset = () => {
    useDesignStore.getState().resetDesign();
  };

  return (
    <div className="relative w-screen h-screen">
      {/* 3D Canvas fills the viewport — touch-action: none prevents
          browser scroll/zoom gestures on touch devices */}
      <div className="canvas-container w-full h-full">
        <Scene beads={beads} />
      </div>

      {/* ── Overlay UI ──────────────────────────────────────────────── */}

      {/* Title */}
      <div className="absolute top-4 left-4 select-none pointer-events-none">
        <h1 className="text-lg font-semibold text-gray-700 tracking-tight">
          Bead Chain
        </h1>
        <p className="text-xs text-gray-400 mt-0.5">
          Drag beads to interact
        </p>
      </div>

      {/* Controls panel */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 rounded-full bg-white/70 backdrop-blur-md shadow-lg px-4 py-2 border border-gray-200/50">
        <span className="text-sm text-gray-500 mr-2">{beads.length} beads</span>

        <button
          onClick={handleAdd}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-emerald-50 text-emerald-700 hover:bg-emerald-100 transition-colors cursor-pointer"
        >
          + Add
        </button>

        <button
          onClick={handleRemoveLast}
          disabled={beads.length === 0}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-rose-50 text-rose-700 hover:bg-rose-100 transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
        >
          − Remove
        </button>

        <button
          onClick={handleReset}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-gray-50 text-gray-700 hover:bg-gray-100 transition-colors cursor-pointer"
        >
          ↺ Reset
        </button>
      </div>
    </div>
  );
}

/**
 * Performance Baseline (S02/T03):
 * - Device: Galaxy S24 emulation (360×780, Playwright), Desktop Edge (1280×720)
 * - Beads: 20+
 * - FPS: 60 (mobile emulation, no CPU throttle), 60 (desktop)
 * - Mitigations applied: none (optimizations sufficient)
 * - Sphere segments: 24 (down from 32)
 * - Thread curve points: 20 (down from 32)
 * - ContactShadows resolution: 256 (down from 512)
 *
 * Note: CPU throttling (4× slowdown) is a Chrome DevTools-only feature not available
 * via Playwright. Desktop + mobile emulation at native clock both sustain 60 FPS with
 * 20+ beads, providing substantial headroom above the 30 FPS target.
 */
"use client";

import { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { Physics } from "@react-three/rapier";
import {
  OrbitControls,
  Environment,
  ContactShadows,
  Stats,
} from "@react-three/drei";
import { BeadChain } from "./BeadChain";
import AdaptiveRenderer from "./AdaptiveRenderer";
import { useDragStore } from "@/lib/dragStore";
import type { BeadState } from "@/types/bead";

export interface SceneProps {
  /** Array of bead descriptors — drives chain composition. */
  beads: BeadState[];
}

/**
 * OrbitControls wrapper that reads the shared drag flag and disables
 * orbit rotation while a bead is being dragged. This prevents the scene
 * from rotating simultaneously with the bead drag gesture on touch devices.
 *
 * Uses the Zustand hook so React re-renders this component when the flag
 * changes — OrbitControls picks up the new `enabled` prop immediately.
 */
function DragAwareOrbitControls() {
  const isDragging = useDragStore((s) => s.isDragging);
  return (
    <OrbitControls
      makeDefault
      minPolarAngle={0}
      maxPolarAngle={Math.PI}
      minDistance={2}
      maxDistance={20}
      enabled={!isDragging}
    />
  );
}

/**
 * Root 3D scene: Canvas → Physics → BeadChain → ThreadLine.
 * SSR-safe (loaded via SceneLoader with dynamic ssr:false).
 */
export default function Scene({ beads }: SceneProps) {
  return (
    <Canvas
      camera={{ position: [0, 1, 7], fov: 50 }}
      shadows
      style={{ background: "linear-gradient(180deg, #f0f4f8 0%, #d9e2ec 100%)" }}
    >
      {/* Soft gradient background */}
      <color attach="background" args={["#eef2f6"]} />
      <fog attach="fog" args={["#eef2f6", 12, 22]} />

      {/* Lighting: soft studio feel */}
      <ambientLight intensity={0.3} />
      <directionalLight
        position={[5, 8, 5]}
        intensity={1}
        castShadow
        shadow-mapSize-width={1024}
        shadow-mapSize-height={1024}
      />
      {/* Fill light from opposite side for softer shadows */}
      <directionalLight position={[-3, 5, -3]} intensity={0.3} />

      {/* Adaptive rendering — must be inside Canvas for R3F context */}
      <AdaptiveRenderer />

      <Suspense fallback={null}>
        <Environment preset="studio" />

        {/* Physics world: gravity tuned for snappy feel (Vercel pattern) */}
        <Physics gravity={[0, -40, 0]}>
          <BeadChain beads={beads} anchorPosition={[0, 3, 0]} />
        </Physics>

        {/* Soft ground shadow — resolution 256 for perf (default 512) */}
        <ContactShadows
          position={[0, -3, 0]}
          opacity={0.4}
          scale={10}
          blur={2}
          far={4}
          resolution={256}
        />
      </Suspense>

      <DragAwareOrbitControls />

      {/* FPS overlay — visible in dev only */}
      <Stats />
    </Canvas>
  );
}

import SceneLoader from "@/components/SceneLoader";

export default function Home() {
  return <SceneLoader />;
}

import { create } from "zustand";
import type { BeadState } from "@/types/bead";
import { CATALOG_BEADS } from "@/data/catalogBeads";
import { catalogBeadToBeadState } from "@/lib/catalogUtils";

// ── Default chain ────────────────────────────────────────────────────────────
// Same 7 default beads as useBeadChain's DEFAULT_BEADS.

const DEFAULT_BEADS: BeadState[] = [
  { id: "bead-1", type: "wood", radius: 0.2, color: "#D4A574" },
  { id: "bead-2", type: "silicone", radius: 0.18, color: "#FF6B9D" },
  { id: "bead-3", type: "wood", radius: 0.22, color: "#C4956A" },
  { id: "bead-4", type: "plastic", radius: 0.19, color: "#6EC1E4" },
  { id: "bead-5", type: "wood", radius: 0.21, color: "#B8860B" },
  { id: "bead-6", type: "silicone", radius: 0.17, color: "#E8A0BF" },
  { id: "bead-7", type: "wood", radius: 0.2, color: "#DEB887" },
];

const MAX_CHAIN_LENGTH = 40;

// ── Store interface ──────────────────────────────────────────────────────────

export interface DesignState {
  beads: BeadState[];
  selectedBeadId: string | null;
  productType: "pacifier-holder";

  addBead: (catalogBeadId: string) => void;
  removeBead: (id: string) => void;
  removeSelected: () => void;
  selectBead: (id: string | null) => void;
  resetDesign: () => void;
}

// ── Store ────────────────────────────────────────────────────────────────────

export const useDesignStore = create<DesignState>((set, get) => ({
  beads: DEFAULT_BEADS,
  selectedBeadId: null,
  productType: "pacifier-holder",

  addBead: (catalogBeadId: string) => {
    if (get().beads.length >= MAX_CHAIN_LENGTH) return;

    const catalogBead = CATALOG_BEADS.find((b) => b.id === catalogBeadId);
    if (!catalogBead) return;

    const beadState = catalogBeadToBeadState(catalogBead);
    set((state) => ({ beads: [...state.beads, beadState] }));
  },

  removeBead: (id: string) => {
    set((state) => {
      const removed = state.beads.find((b) => b.id === id);
      return {
        beads: state.beads.filter((b) => b.id !== id),
        selectedBeadId: removed?.id === state.selectedBeadId ? null : state.selectedBeadId,
      };
    });
  },

  removeSelected: () => {
    const { selectedBeadId } = get();
    if (!selectedBeadId) return;

    set((state) => ({
      beads: state.beads.filter((b) => b.id !== selectedBeadId),
      selectedBeadId: null,
    }));
  },

  selectBead: (id: string | null) => {
    set({ selectedBeadId: id });
  },

  resetDesign: () => {
    set({ beads: DEFAULT_BEADS, selectedBeadId: null });
  },
}));

import { describe, it, expect, beforeEach } from "vitest";
import { useDesignStore } from "../useDesignStore";
import { CATALOG_BEADS } from "@/data/catalogBeads";

describe("useDesignStore", () => {
  beforeEach(() => {
    useDesignStore.getState().resetDesign();
  });

  it("initializes with 7 beads, selectedBeadId null, productType pacifier-holder", () => {
    const state = useDesignStore.getState();
    expect(state.beads).toHaveLength(7);
    expect(state.selectedBeadId).toBeNull();
    expect(state.productType).toBe("pacifier-holder");
  });

  it("all default beads have required fields (id, type, radius, color)", () => {
    const { beads } = useDesignStore.getState();
    for (const bead of beads) {
      expect(bead).toHaveProperty("id");
      expect(bead).toHaveProperty("type");
      expect(bead).toHaveProperty("radius");
      expect(bead).toHaveProperty("color");
      expect(typeof bead.id).toBe("string");
      expect(bead.id).toBeTruthy();
      expect(["wood", "silicone", "knit", "plastic"]).toContain(bead.type);
      expect(typeof bead.radius).toBe("number");
      expect(bead.radius).toBeGreaterThan(0);
      expect(typeof bead.color).toBe("string");
      expect(bead.color).toBeTruthy();
    }
  });

  it("addBead(catalogBeadId) increases bead count by 1", () => {
    // Use a real catalog bead id
    const catalogId = CATALOG_BEADS[0].id;
    const before = useDesignStore.getState().beads.length;

    useDesignStore.getState().addBead(catalogId);

    expect(useDesignStore.getState().beads).toHaveLength(before + 1);
  });

  it("addBead(catalogBeadId) correctly converts CatalogBead → BeadState", () => {
    const catalogBead = CATALOG_BEADS[0];
    useDesignStore.getState().addBead(catalogBead.id);

    const lastBead = useDesignStore.getState().beads.at(-1)!;
    expect(lastBead.catalogBeadId).toBe(catalogBead.id);
    expect(lastBead.type).toBe(catalogBead.material);
    expect(lastBead.color).toBe(catalogBead.color);
    // radius = catalog size * 0.8 (from catalogBeadToBeadState)
    expect(lastBead.radius).toBeCloseTo(catalogBead.size * 0.8, 5);
    expect(typeof lastBead.id).toBe("string");
    expect(lastBead.id).toBeTruthy();
  });

  it("addBead('nonexistent') is a no-op", () => {
    const before = useDesignStore.getState().beads.length;
    useDesignStore.getState().addBead("nonexistent");
    expect(useDesignStore.getState().beads).toHaveLength(before);
  });

  it("addBead beyond max (40) is a no-op", () => {
    // Reset to 7 default, add beads until we reach 40
    useDesignStore.getState().resetDesign();
    const firstCatalogId = CATALOG_BEADS[0].id;

    // Add 33 more beads to reach exactly 40 (7 + 33 = 40)
    for (let i = 0; i < 33; i++) {
      useDesignStore.getState().addBead(firstCatalogId);
    }
    expect(useDesignStore.getState().beads).toHaveLength(40);

    // This one should be a no-op
    useDesignStore.getState().addBead(firstCatalogId);
    expect(useDesignStore.getState().beads).toHaveLength(40);
  });

  it("removeBead(id) decreases count and removes correct bead", () => {
    const targetId = useDesignStore.getState().beads[2].id;
    const before = useDesignStore.getState().beads.length;

    useDesignStore.getState().removeBead(targetId);

    const after = useDesignStore.getState();
    expect(after.beads).toHaveLength(before - 1);
    expect(after.beads.find((b) => b.id === targetId)).toBeUndefined();
  });

  it("removeBead with unknown id is a no-op", () => {
    const before = useDesignStore.getState().beads.length;
    useDesignStore.getState().removeBead("nonexistent-id");
    expect(useDesignStore.getState().beads).toHaveLength(before);
  });

  it("selectBead('id') sets selectedBeadId", () => {
    const beadId = useDesignStore.getState().beads[0].id;
    useDesignStore.getState().selectBead(beadId);
    expect(useDesignStore.getState().selectedBeadId).toBe(beadId);
  });

  it("selectBead(null) clears selection", () => {
    const beadId = useDesignStore.getState().beads[0].id;
    useDesignStore.getState().selectBead(beadId);
    expect(useDesignStore.getState().selectedBeadId).toBe(beadId);

    useDesignStore.getState().selectBead(null);
    expect(useDesignStore.getState().selectedBeadId).toBeNull();
  });

  it("removeSelected() removes the selected bead and clears selection", () => {
    const beadId = useDesignStore.getState().beads[0].id;
    useDesignStore.getState().selectBead(beadId);
    const before = useDesignStore.getState().beads.length;

    useDesignStore.getState().removeSelected();

    const after = useDesignStore.getState();
    expect(after.beads).toHaveLength(before - 1);
    expect(after.selectedBeadId).toBeNull();
    expect(after.beads.find((b) => b.id === beadId)).toBeUndefined();
  });

  it("removeSelected() with no selection is a no-op", () => {
    const before = useDesignStore.getState();
    expect(before.selectedBeadId).toBeNull();
    const count = before.beads.length;

    useDesignStore.getState().removeSelected();

    expect(useDesignStore.getState().beads).toHaveLength(count);
    expect(useDesignStore.getState().selectedBeadId).toBeNull();
  });

  it("resetDesign() returns to 7 default beads and clears selection", () => {
    // Modify the state
    useDesignStore.getState().addBead(CATALOG_BEADS[0].id);
    useDesignStore.getState().addBead(CATALOG_BEADS[1].id);
    useDesignStore.getState().selectBead(useDesignStore.getState().beads[0].id);

    expect(useDesignStore.getState().beads.length).not.toBe(7);
    expect(useDesignStore.getState().selectedBeadId).not.toBeNull();

    // Reset
    useDesignStore.getState().resetDesign();

    const after = useDesignStore.getState();
    expect(after.beads).toHaveLength(7);
    expect(after.selectedBeadId).toBeNull();
    // Verify default beads are restored
    expect(after.beads[0].id).toBe("bead-1");
    expect(after.beads[6].id).toBe("bead-7");
  });

  it("removeBead clears selection if removed bead was selected", () => {
    const beadId = useDesignStore.getState().beads[3].id;
    useDesignStore.getState().selectBead(beadId);
    expect(useDesignStore.getState().selectedBeadId).toBe(beadId);

    useDesignStore.getState().removeBead(beadId);

    expect(useDesignStore.getState().selectedBeadId).toBeNull();
  });

  it("removeBead does not clear selection for a different bead", () => {
    const selectedId = useDesignStore.getState().beads[0].id;
    const otherId = useDesignStore.getState().beads[1].id;
    useDesignStore.getState().selectBead(selectedId);

    useDesignStore.getState().removeBead(otherId);

    expect(useDesignStore.getState().selectedBeadId).toBe(selectedId);
  });
});

"use client";

import { useMemo } from "react";
import { RigidBody, BallCollider, useRopeJoint } from "@react-three/rapier";
import type { RapierRigidBody } from "@react-three/rapier";
import type { BeadState } from "@/types/bead";
import { BeadRigidBody } from "./BeadRigidBody";
import { ThreadLine } from "./ThreadLine";

// ── Constants ────────────────────────────────────────────────────────────────

/** Vertical distance between consecutive bead centres (world units). */
const BEAD_SPACING = 0.8;

/**
 * Rope max-length factor relative to BEAD_SPACING.
 * < 1.0 keeps the rope slightly taut (tension).
 */
const ROPE_TAUT_FACTOR = 0.92;

/** Radius of the fixed anchor ball. */
const ANCHOR_RADIUS = 0.12;

// ── JointLink ────────────────────────────────────────────────────────────────

/**
 * Thin wrapper that calls `useRopeJoint` for a single pair of bodies.
 * MUST be a separate component because React hooks cannot be called in loops.
 */
function JointLink({
  bodyA,
  bodyB,
  length,
}: {
  bodyA: React.RefObject<RapierRigidBody | null>;
  bodyB: React.RefObject<RapierRigidBody | null>;
  length: number;
}) {
  useRopeJoint(
    bodyA as React.RefObject<RapierRigidBody>,
    bodyB as React.RefObject<RapierRigidBody>,
    [[0, 0, 0], [0, 0, 0], length],
  );
  return null;
}

// ── BeadChain ────────────────────────────────────────────────────────────────

export interface BeadChainProps {
  /** Array of bead descriptors (position is computed from index). */
  beads: BeadState[];
  /** World-space position of the fixed anchor point. */
  anchorPosition: [number, number, number];
  /** Thread colour (default: "#8B4513" — saddle brown). */
  threadColor?: string;
}

/**
 * Full physics bead chain: fixed anchor → N dynamic beads connected by rope
 * joints → MeshLine thread that follows bead positions every frame.
 */
export function BeadChain({
  beads,
  anchorPosition,
  threadColor = "#8B4513",
}: BeadChainProps) {
  const [ax, ay, az] = anchorPosition;

  // ── Stable ref for the fixed anchor ───────────────────────────────────
  const anchorRef = useMemo(
    () => ({ current: null as RapierRigidBody | null }),
    [],
  );

  // ── Pre-create a stable ref object for every bead ─────────────────────
  // useMemo keyed on array length: new refs only when count changes.
  const beadRefs = useMemo(
    () =>
      beads.map(
        () => ({ current: null as RapierRigidBody | null }),
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [beads.length],
  );

  // ── Compute initial bead positions (vertical column) ──────────────────
  const beadPositions = useMemo(
    () =>
      beads.map(
        (_, i) =>
          [ax, ay - (i + 1) * BEAD_SPACING, az] as [number, number, number],
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [beads.length, ax, ay, az],
  );

  const ropeLength = BEAD_SPACING * ROPE_TAUT_FACTOR;

  return (
    <group>
      {/* ── Fixed anchor ─────────────────────────────────────────────── */}
      <RigidBody ref={anchorRef} type="fixed" position={anchorPosition}>
        <BallCollider args={[ANCHOR_RADIUS]} />
        <mesh>
          <sphereGeometry args={[ANCHOR_RADIUS, 24, 24]} />
          <meshStandardMaterial color="#444444" roughness={0.5} metalness={0.4} />
        </mesh>
      </RigidBody>

      {/* ── Dynamic beads ───────────────────────────────────────────── */}
      {beads.map((bead, i) => (
        <BeadRigidBody
          key={bead.id}
          ref={beadRefs[i]}
          radius={bead.radius}
          color={bead.color}
          type={bead.type}
          damping={2}
          position={beadPositions[i]}
        />
      ))}

      {/* ── Rope joints ─────────────────────────────────────────────── */}
      {/* anchor → bead[0] */}
      {beads.length > 0 && (
        <JointLink
          bodyA={anchorRef}
          bodyB={beadRefs[0]}
          length={ropeLength}
        />
      )}
      {/* bead[i] → bead[i+1] */}
      {beads.slice(1).map((bead, i) => (
        <JointLink
          key={`joint-${bead.id}`}
          bodyA={beadRefs[i]}
          bodyB={beadRefs[i + 1]}
          length={ropeLength}
        />
      ))}

      {/* ── Thread line visualisation ───────────────────────────────── */}
      <ThreadLine
        anchorPosition={anchorPosition}
        anchorRef={anchorRef}
        beadRefs={beadRefs}
        beadCount={beads.length}
        color={threadColor}
      />
    </group>
  );
}

